scripts:
(function(){
  function applyPricingCardVars(scope){
    var cards = scope.querySelectorAll('.pricing-card');
    cards.forEach(function(card){
      var accent = card.getAttribute('data-accent');
      var excluded = card.getAttribute('data-excluded');
      var bg = card.getAttribute('data-card-bg');

      if (bg) {
        card.style.backgroundColor = bg;
      }

      if (accent) {
        var price = card.querySelector('.pricing-card__price');
        var button = card.querySelector('.pricing-card__button');
        var includedIcons = card.querySelectorAll('.pricing-card__feature.is-included .pricing-card__feature-icon');

        if (price) {
          price.style.color = accent;
        }

        if (button) {
          button.style.backgroundColor = accent;
        }

        includedIcons.forEach(function(icon){
          icon.style.color = accent;
        });
      }

      if (excluded) {
        var excludedIcons = card.querySelectorAll('.pricing-card__feature.is-excluded .pricing-card__feature-icon');
        excludedIcons.forEach(function(icon){
          icon.style.color = excluded;
        });
      }
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function(){
      applyPricingCardVars(document);
    });
  } else {
    applyPricingCardVars(document);
  }
})();

styles:
:root {
  display: block;
  font-family: var(--main-font, 16px), Arial, Helvetica, sans-serif;
  color: #5f6166;
}

:root .pricing-card,
:root .pricing-card * {
  box-sizing: border-box;
}

:root .pricing-card {
  background: #f3f3f3;
  border-radius: 14px;
  padding: 54px 38px 86px;
  text-align: center;
  color: #5f6166;
  max-width: 520px;
  display: flex;
  flex-direction: column;
  align-items: center;
}

:root .pricing-card__icon {
  width: 96px;
  height: 96px;
  margin: 0 auto 32px;
  color: #666666;
  display: flex;
  align-items: center;
  justify-content: center;
}

:root .pricing-card__icon svg,
:root .pricing-card__icon img {
  display: block;
  width: 100%;
  height: 100%;
}

:root .pricing-card__icon img {
  object-fit: contain;
}

:root .pricing-card__title {
  margin: 0;
  font-size: 38px;
  line-height: 1.08;
  font-weight: 800;
  letter-spacing: -0.03em;
  color: #25273b;
}

:root .pricing-card__price {
  margin-top: 28px;
  font-size: 84px;
  line-height: 0.95;
  font-weight: 800;
  letter-spacing: -0.04em;
  color: #27b04b;
}

:root .pricing-card__note {
  margin-top: 28px;
  font-size: 34px;
  line-height: 1.15;
  font-weight: 700;
  letter-spacing: -0.03em;
  color: #666666;
}

:root .pricing-card__features {
  list-style: none;
  padding: 0;
  margin: 62px 0 0;
  width: 100%;
}

:root .pricing-card__feature {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 14px;
  margin: 0;
  color: #666666;
}

:root .pricing-card__feature + .pricing-card__feature {
  margin-top: 26px;
}

:root .pricing-card__feature-icon {
  flex: 0 0 auto;
  width: 34px;
  height: 34px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: #27b04b;
}

:root .pricing-card__feature.is-excluded .pricing-card__feature-icon {
  color: #9a4b4b;
}

:root .pricing-card__feature-icon svg {
  width: 100%;
  height: 100%;
  display: block;
}

:root .pricing-card__feature-text {
  font-size: 32px;
  line-height: 1.2;
  font-weight: 500;
  letter-spacing: -0.03em;
}

:root .pricing-card__cta {
  width: 100%;
  margin-top: 84px;
  display: flex;
  justify-content: center;
  clear: both;
}

:root .pricing-card__button {
  min-width: 300px;
  max-width: 100%;
  text-align: center;
  background: #27b04b;
  border-radius: 999px;
  color: #ffffff;
  font-size: 28px;
  line-height: 1.1;
  font-weight: 800;
  padding: 28px 44px;
  text-decoration: none;
  position: relative;
  z-index: 1;
}

:root .pricing-card__button:hover,
:root .pricing-card__button:focus-visible {
  background: #1f973f;
  color: #ffffff;
}

@media (max-width: 767px) {
  :root .pricing-card {
    padding: 38px 24px 52px;
  }

  :root .pricing-card__icon {
    width: 82px;
    height: 82px;
    margin-bottom: 24px;
  }

  :root .pricing-card__title {
    font-size: 30px;
  }

  :root .pricing-card__price {
    margin-top: 22px;
    font-size: 64px;
  }

  :root .pricing-card__note {
    margin-top: 20px;
    font-size: 26px;
  }

  :root .pricing-card__features {
    margin-top: 44px;
  }

  :root .pricing-card__feature {
    justify-content: flex-start;
    gap: 12px;
  }

  :root .pricing-card__feature-text {
    font-size: 24px;
  }

  :root .pricing-card__cta {
    margin-top: 56px;
  }

  :root .pricing-card__button {
    min-width: 0;
    width: 100%;
    font-size: 24px;
    padding: 22px 28px;
  }
}
